using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents use "Discriminator", so preserve it.
            entity.HasDiscriminator().HasValue("Blog");
            entity.Property<string>("$type").ToJsonProperty("Discriminator");

            // Breaking change 2: EF 9 changed id format from "EntityName|KeyValue" to just "KeyValue".
            // Existing documents use "Blog|<key>", so preserve the old format.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyIdValueGenerator>();

            // Breaking change 3: Cosmos DB does not support indexes defined via EF.
            // HasIndex() now throws in EF 9 instead of being silently ignored.
            // Removed: entity.HasIndex(b => b.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; }

